static void lsr_delete_anim_value(GF_LASeRCodec *lsr, SMIL_AnimateValue *val, u32 coded_type)
{
	//unable to transform, free mem and reset
	switch (coded_type) {
	case 0://SVG_string *
		gf_free(* (SVG_String *)val->value);
		gf_free(val->value);
